with recursive
m_sum as(
select month, sum(amount)::integer from factory
group by month
order by month),
rec(cur_month, last_amount, next_amount, delta_amount) as( 
	select 0, 0, 0, 0
	union all
	select (rec.cur_month + 1), rec.next_amount, rec.next_amount + m_sum2.sum, m_sum2.sum from rec
	join m_sum as m_sum2 on (rec.cur_month + 1) = m_sum2.month
	where (rec.cur_month + 1) > 0
) 
select * from rec
where rec.cur_month > 0;







